const items = $input.all();
const results = [];
for (const item of items) {
  const vendedor = item.json;
  const conversasResumo = Array.isArray(vendedor.conversas_resumo)
    ? vendedor.conversas_resumo.slice(0, 20)
    : [];
  const prompt = `Avalie o perfil profissional do colaborador com base nas suas conversas de atendimento e retorne um JSON com:\n- dimensoes: objeto com scores de 0 a 100 para cada dimensão {comunicacao, execucao, iniciativa, qualidade, relacionamento}\n- score_aderencia: número de 0 a 100 representando aderência geral ao perfil ideal\n- pontos_fortes: array de strings com os 3-5 principais pontos fortes identificados\n- gaps_identificados: array de strings com os 2-4 principais gaps ou áreas de desenvolvimento\n\nDados do colaborador:\n- Nome: ${vendedor.vendedor_nome}\n- Função: ${vendedor.funcao}\n- Total de conversas nos últimos 60 dias: ${vendedor.total_conversas}\n- Score médio de qualidade: ${vendedor.score_medio}\n- Total convertidos: ${vendedor.total_convertidos}\n- Taxa de conversão: ${vendedor.taxa_conversao}%\n- Amostra de conversas recentes: ${JSON.stringify(conversasResumo)}\n\nRetorne APENAS o JSON, sem explicações.`;
  results.push({
    json: {
      vendedor_id: String(vendedor.vendedor_id),
      vendedor_nome: vendedor.vendedor_nome,
      funcao: vendedor.funcao,
      total_conversas: vendedor.total_conversas,
      score_medio: vendedor.score_medio,
      taxa_conversao: vendedor.taxa_conversao,
      prompt
    }
  });
}
return results;

const response = $input.first().json;
const content = response.content?.[0]?.text || '{}';
let parsed;
try { parsed = JSON.parse(content); } catch(e) { parsed = {erro: 'parse_failed', raw: content.substring(0,200)}; }
return [{json: {...$input.first().json, resultado: parsed}}];
